const {
  withAndroidManifest,
  withAppBuildGradle,
  withDangerousMod,
  withMainApplication,
} = require("@expo/config-plugins");
const fs = require("fs");
const path = require("path");

function addAccentColors(projectRoot) {
  const resDir = path.join(projectRoot, "android", "app", "src", "main", "res");

  // Light mode
  const valuesDir = path.join(resDir, "values");
  const lightFile = path.join(valuesDir, "colors.xml");
  const lightEntries = `
  <!-- Folio accent colors -->
  <color name="accent_light">#02807A</color>
  <color name="accent_dark">#016961</color>
</resources>`;

  if (!fs.existsSync(valuesDir)) fs.mkdirSync(valuesDir, { recursive: true });
  if (fs.existsSync(lightFile)) {
    let xml = fs.readFileSync(lightFile, "utf8");
    if (!xml.includes("accent_light")) {
      xml = xml.replace(/<\/resources>/, lightEntries);
      fs.writeFileSync(lightFile, xml);
    }
  } else {
    fs.writeFileSync(
      lightFile,
      `<?xml version="1.0" encoding="utf-8"?>
<resources>${lightEntries}`,
    );
  }

  // Night mode
  const nightDir = path.join(resDir, "values-night");
  const nightFile = path.join(nightDir, "colors.xml");
  const nightXml = `<?xml version="1.0" encoding="utf-8"?>
<resources>
  <!-- Folio accent colors (night) -->
  <color name="accent_light">#02807A</color>
  <color name="accent_dark">#016961</color>
</resources>`;

  if (!fs.existsSync(nightDir)) fs.mkdirSync(nightDir, { recursive: true });
  if (!fs.existsSync(nightFile)) {
    fs.writeFileSync(nightFile, nightXml);
  }
}

/**
 * Expo Config Plugin for Folio Share functionality
 * Automatically creates ShareActivity, SimpleTokenManager, and required resources
 */
const withFolioShareAndroid = (config, options = {}) => {
  // Add Android Manifest modifications
  config = withAndroidManifest(config, (config) => {
    const androidManifest = config.modResults;
    const mainApplication = androidManifest.manifest.application[0];

    // Add ShareActivity to AndroidManifest.xml
    const shareActivity = {
      "$": {
        "android:name": ".ShareActivity",
        "android:label": "Save to Folio",
        "android:icon": "@mipmap/ic_launcher",
        "android:theme": "@android:style/Theme.Translucent.NoTitleBar",
        "android:exported": "true",
        "android:excludeFromRecents": "true",
        "android:taskAffinity": "",
        "android:launchMode": "singleInstance",
      },
      "intent-filter": [
        {
          action: [{ $: { "android:name": "android.intent.action.SEND" } }],
          category: [{ $: { "android:name": "android.intent.category.DEFAULT" } }],
          data: [{ $: { "android:mimeType": "text/plain" } }],
        },
        {
          action: [{ $: { "android:name": "android.intent.action.SEND" } }],
          category: [{ $: { "android:name": "android.intent.category.DEFAULT" } }],
          data: [{ $: { "android:mimeType": "text/*" } }],
        },
      ],
    };

    // Add the activity to the application if it doesn't exist
    if (!mainApplication.activity) {
      mainApplication.activity = [];
    }

    // Check if ShareActivity already exists
    const hasShareActivity = mainApplication.activity.some(
      (activity) => activity.$["android:name"] === ".ShareActivity",
    );

    if (!hasShareActivity) {
      mainApplication.activity.push(shareActivity);
    }

    // Add permissions
    if (!androidManifest.manifest["uses-permission"]) {
      androidManifest.manifest["uses-permission"] = [];
    }

    const permissions = ["android.permission.VIBRATE", "android.permission.INTERNET"];
    permissions.forEach((permission) => {
      const hasPermission = androidManifest.manifest["uses-permission"].some(
        (p) => p.$["android:name"] === permission,
      );
      if (!hasPermission) {
        androidManifest.manifest["uses-permission"].push({
          $: { "android:name": permission },
        });
      }
    });

    return config;
  });

  // Add build.gradle dependencies
  config = withAppBuildGradle(config, (config) => {
    const buildGradle = config.modResults.contents;

    const dependencies = [
      "com.squareup.okhttp3:okhttp:4.12.0",
      "org.jetbrains.kotlinx:kotlinx-coroutines-android:1.7.3",
      "com.github.bumptech.glide:glide:4.16.0",
    ];

    let dependenciesToAdd = [];
    dependencies.forEach((dep) => {
      const depName = dep.split(":")[0] + ":" + dep.split(":")[1];
      if (!buildGradle.includes(depName)) {
        dependenciesToAdd.push(`    implementation("${dep}")`);
      }
    });

    if (dependenciesToAdd.length > 0) {
      const dependenciesRegex = /(dependencies\s*{[\s\S]*?)(}(?=\s*$|\s*\w+\s*{))/;
      const match = buildGradle.match(dependenciesRegex);

      if (match) {
        const newDependencies = dependenciesToAdd.join("\n");
        config.modResults.contents = buildGradle.replace(
          dependenciesRegex,
          `${match[1]}\n${newDependencies}\n${match[2]}`,
        );
      }
    }

    return config;
  });

  // Add TokenManager to MainApplication.kt
  config = withMainApplication(config, (config) => {
    const { modResults } = config;
    let content = modResults.contents;

    // Add import if missing
    if (!content.includes("import co.lessisbetter.folio.TokenManagerPackage")) {
      content = content.replace(
        /(import com\.facebook\.soloader\.SoLoader)/,
        "$1\nimport co.lessisbetter.folio.TokenManagerPackage",
      );
    }

    // Add package registration if missing - target the return packages line
    if (!content.includes("packages.add(TokenManagerPackage())")) {
      console.log("🔍 TokenManager package not found, attempting to add it...");
      const beforeReplace = content;
      content = content.replace(
        /(\s+)return packages/,
        "$1// Add our custom TokenManager package\n$1packages.add(TokenManagerPackage())\n$1return packages",
      );
      if (beforeReplace === content) {
        console.log("❌ Regex replacement failed - 'return packages' pattern didn't match");
      } else {
        console.log("✅ TokenManager package added successfully before return statement");
      }
    } else {
      console.log("ℹ️ TokenManager package already present");
    }

    config.modResults.contents = content;
    return config;
  });

  config = withDangerousMod(config, [
    "android",
    async (modConfig) => {
      await createKotlinFiles(modConfig.modRequest.projectRoot);
      await createDrawableResources(modConfig.modRequest.projectRoot);
      addAccentColors(modConfig.modRequest.projectRoot);
      return modConfig;
    },
  ]);

  return config;
};

/**
 * Copies Android template files to project
 */
async function createKotlinFiles(projectRoot) {
  const templateDir = path.join(__dirname, "folio-share-android-template");
  const kotlinDir = path.join(
    projectRoot,
    "android",
    "app",
    "src",
    "main",
    "java",
    "co",
    "lessisbetter",
    "folio",
  );

  console.log("🔧 Adding Android share functionality from template...");
  console.log("📍 Template source:", templateDir);
  console.log("📍 Android target:", kotlinDir);

  // Create directory if it doesn't exist
  if (!fs.existsSync(kotlinDir)) {
    fs.mkdirSync(kotlinDir, { recursive: true });
  }

  // Verify template exists
  if (!fs.existsSync(templateDir)) {
    throw new Error(`Android template not found at: ${templateDir}`);
  }

  // Copy template files to target directory
  const templateFiles = [
    "ShareActivity.kt",
    "SimpleTokenManager.kt",
    "TokenManager.kt",
    "TokenManagerPackage.kt",
  ];

  for (const fileName of templateFiles) {
    const templateFile = path.join(templateDir, fileName);
    const targetFile = path.join(kotlinDir, fileName);

    if (!fs.existsSync(templateFile)) {
      throw new Error(`Template file not found: ${templateFile}`);
    }

    console.log(`📄 Copying ${fileName}...`);
    fs.copyFileSync(templateFile, targetFile);
  }

  console.log("✅ Created Kotlin source files from templates in:", kotlinDir);
}

